function TodoList({ todos, showDone }: { todos: { id: string; text: string; done: boolean }[]; showDone: boolean }) {
  return (
    <ul>
      {todos
        .filter((todo) => showDone || !todo.done)
        .map((todo) => (
          <li key={todo.id}>{todo.text}</li>
        ))}
    </ul>
  );
}

