function Counter() {
  const [count, setCount] = useState(0);

  function handleClick() {
    setCount(count + 1);
    setCount(count + 1);
    setCount(count + 1);
  }

  function handleSafeClick() {
    setCount((prev) => prev + 1);
    setCount((prev) => prev + 1);
    setCount((prev) => prev + 1);
  }

  return (
    <>
      <p>{count}</p>
      <button onClick={handleClick}>naive +3</button>
      <button onClick={handleSafeClick}>safe +3</button>
    </>
  );
}

