import { useSyncExternalStore } from 'react';

function useOnlineStatus() {
  return useSyncExternalStore(
    (subscribe) => {
      window.addEventListener('online', subscribe);
      window.addEventListener('offline', subscribe);
      return () => {
        window.removeEventListener('online', subscribe);
        window.removeEventListener('offline', subscribe);
      };
    },
    () => navigator.onLine,
    () => true
  );
}

function SearchPage() {
  const [query, setQuery] = useState('');
  const deferredQuery = useDeferredValue(query);
  const isStale = query !== deferredQuery;

  return (
    <>
      <input value={query} onChange={(event) => setQuery(event.target.value)} />
      <Suspense fallback={<p>Loading results…</p>}>
        <div style={{ opacity: isStale ? 0.5 : 1 }}>
          <SearchResults query={deferredQuery} />
        </div>
      </Suspense>
    </>
  );
}

import { useActionState } from 'react';
import { useFormStatus } from 'react-dom';

function SubmitButton() {
  const { pending } = useFormStatus();
  return <button disabled={pending}>{pending ? 'Saving…' : 'Save'}</button>;
}

async function saveProfile(prevState: { error: string | null }, formData: FormData) {
  const name = formData.get('name');
  if (!name) {
    return { error: 'Name is required' };
  }

  await api.save({ name });
  return { error: null };
}

function ProfileForm() {
  const [state, formAction, isPending] = useActionState(saveProfile, { error: null });

  return (
    <form action={formAction}>
      <input name='name' />
      {state.error && <p>{state.error}</p>}
      <SubmitButton />
      {isPending && <p>Saving profile…</p>}
    </form>
  );
}

